const raw = $('Read For Archive').first().json.stdout.split('---SPLIT---');
const state = JSON.parse(raw[0]);
const log = raw[1].trim();
const digest = $input.first().json.text || $input.first().json.content?.parts?.[0]?.text || '';

const active = state.session.status === 'active';
const now = new Date();
const il = new Intl.DateTimeFormat('en-CA', { timeZone: 'Asia/Jerusalem' });
const fname = `archive/${il.format(now)}-session${state.session.number}.md`;

if (active) {
  state.session.status = 'ended';
  state.last_session.archive_file = fname;
  state.last_session.ended_at = now.toISOString();
  // Reset flow state on session close
  state.flow = { position: null, current_task: null, timer: null, frozen: false };
}

const archive = digest.trim() + '\n\n<!-- RAW-LOG -->' + log + '\n';

return [{
  json: {
    active,
    fname,
    archiveB64: Buffer.from(archive).toString('base64'),
    stateB64: Buffer.from(JSON.stringify(state, null, 2)).toString('base64')
  }
}];

const resp = $input.first().json;
let text = resp.text || resp.content?.parts?.[0]?.text || '';

const markers = { pos: null, logs: [], freeze: false, unfreeze: false, rejected: [] };
text = text.replace(/\[\[POS:\s*(\S+?)\s*\]\]/g, (_, p) => { markers.pos = p; return ''; });
text = text.replace(/\[\[LOG:\s*(.+?)\s*\]\]/g, (_, l) => {
  const we = l.match(/^\s*window_end\s*=\s*(.+?)\s*$/);
  if (we) {
    const v = we[1].trim();
    const m = v.match(/^([01]?\d|2[0-3])(?::([0-5]\d))?$/); // H, HH, H:MM, HH:MM
    if (m) {
      markers.logs.push(`window_end=${m[1].padStart(2, '0')}:${m[2] || '00'}`);
    } else {
      markers.rejected.push(`window_end=${v}`);
    }
  } else {
    markers.logs.push(l);
  }
  return '';
});
text = text.replace(/\[\[FREEZE\]\]/g, () => { markers.freeze = true; return ''; });
text = text.replace(/\[\[UNFREEZE\]\]/g, () => { markers.unfreeze = true; return ''; });
text = text.trim();

// Telegram MarkdownV2 breaks on unescaped special chars; strip the offenders.
const safeText = text.replace(/[_*\[\]()~`>#+=|{}]/g, '');

return [{
  json: {
    cleanText: text,
    safeText: safeText,
    hasUpdate: markers.pos !== null || markers.logs.length > 0 || markers.freeze || markers.unfreeze,
    pos: markers.pos,
    freeze: markers.freeze,
    unfreeze: markers.unfreeze,
    rejectedWindowEnd: markers.rejected.join(', '),
    logsB64: Buffer.from(markers.logs.join('\n')).toString('base64')
  }
}];

