// Read flow from the POST-Session-Logic state, not the raw on-disk Read State.
const state = JSON.parse(Buffer.from($('Session Logic').first().json.stateB64, 'base64').toString('utf-8'));
const flow = state.flow || { position: null, current_task: null, timer: null, frozen: false };
const pos = flow.position;
const frozen = flow.frozen;
const timer = flow.timer;

const keys = `הערה על מרקרים: המרקרים [[POS: N]], [[POS: done]], [[POS: archive]], [[LOG: key=value]], [[FREEZE]], [[UNFREEZE]] הם חובה — עליך לכתוב אותם בסוף ההודעה כשמתאים. מפתחות מותרים ל-[[LOG]]: window_end, meds, tired, emotional, parked, project, first_task, day_list, tomorrow_notes, timer_minutes, timer_cancel.`;

const tone = `
--- טון ---
דבר ישיר, מדוד וחברי — אבל בלי התלהבות מזויפת ובלי סופרלטיבים.
תגובות בצ'ק-אין: תגובות ענייניות וניטרליות בלבד ("קיבלתי", "הבנתי", "רשמתי"). אל תבריק ולא לחלק שבחים על תשובות שגרתיות.
עידוד מוצדק: שמור עידוד קצר וממוקד לרגעים אמיתיים בלבד — סיום משימה, התגברות על קושי, או סגירת יום.`;

let block;
if (timer && timer.active) {
  if (timer.pinged) {
    block = `--- מצב מענה לתזכורת טיימר ---
הטיימר למשימה "${timer.task}" הסתיים והודעת תזכורת נשלחה ליהודה.
- סווג את תשובתו:
  1. סיימתי / done -> אשר בקצרה, רשום [[LOG: timer_cancel]], ושאל אם לעבור למשימה הבאה או לקחת הפסקה.
  2. לא סיימתי / צריך עוד X דקות -> אשר עניינית, ורשום [[LOG: timer_minutes=N]] (כאשר N הוא מספר הדקות להאריכו).
  3. תקוע -> נהל כמאמן, עזור לשחרר חסמים או לפרק את המשימה. ` + keys;
  } else {
    block = `--- מצב טיימר פעיל ---
הטיימר רץ כרגע למשימה: "${timer.task}".
- אם יהודה כותב שהוא סיים ("סיימתי" / "גמרתי" / "done"): אשר בקצרה, רשום [[LOG: timer_cancel]], ושאל מה הצעד הבא.
- אם יהודה מציין בעיה או מבקש עזרה: הגב כמאמן, עזור לשחרר חסמים או לפרק את המשימה. ` + keys;
  }
} else if (pos === 'eod_1') {
  block = `--- בקרת זרימה: סיכום סוף יום (שלב 1) ---
סקור את הנושאים הפתוחים שנרשמו כ-parked במהלך היום. שאל את יהודה מה ברצונו לעשות איתם. בסיום רשום [[POS: eod_2]]. ` + keys;
} else if (pos === 'eod_2') {
  block = `--- בקרת זרימה: סיכום סוף יום (שלב 2) ---
עבור על מה שנעשה היום מול מה שתוכנן, והדגש הישגים מרכזיים. בסיום רשום [[POS: eod_3]]. ` + keys;
} else if (pos === 'eod_3') {
  block = `--- בקרת זרימה: סיכום סוף יום (שלב 3) ---
רפלקציה והערות למחר. שאל "איך היה היום?" ומה לרשום כהערה לסשן הבא. כשיש תשובה, רשום [[LOG: tomorrow_notes=...]] וסגור את היום ב-[[POS: archive]]. ` + keys;
} else if (pos === null && !frozen) {
  block = `--- בקרת זרימה ---
אינך נמצא כרגע בצ'ק-אין.
- אם יהודה מנסה להפעיל צ'ק-אין (היי / בוקר טוב / להתחיל צ'ק-אין): שאל את שאלה 1 מ-core/morning-flow.md (חלון עבודה), וסיים עם המרקר [[POS: 1]].
- אם יהודה אומר "סיים יום" / "נגמר להיום": אמור משפט פתיחה קצר לסיכום היום, שאל על ה-parked items, וסיים עם המרקר [[POS: eod_1]].
- אם יהודה מבקש להיזכר במידע ("תזכיר לי...", "מה עשינו ב..."): עיין בקטע --- ARCHIVE DIGESTS --- ובתשובות הקודמות והשב עניינית. ` + keys;
} else if (frozen) {
  block = `--- בקרת זרימה: הזרימה מוקפאת ---
הצ'ק-אין הוקפא בשאלה מספר ${pos}.
- קבל אותו בחזרה בחום, בלי לחץ.
- אם הוא מראה שהוא מוכן להמשיך עכשיו — חזור לאותה שאלה מספר ${pos}, וסיים עם המרקר [[UNFREEZE]] בלבד.
- אם הוא עדיין לא מסוגל — תן לגיטימציה מלאה, הישאר מוקפא. ` + keys;
} else {
  const nextPos = (typeof pos === 'number' && pos < 11) ? pos + 1 : 'done';
  block = `--- בקרת זרימה: צ'ק-אין בוקר ---
יהודה משיב כעת על שאלה מספר ${pos} מתוך 11.
- הנחיות לעיבוד תשובה ${pos}:
  * אם ${pos} == 1 (חלון עבודה): המר את תשובת השעה (למשל '16' -> '16:00'), פלוט [[LOG: window_end=16:00]], תן אישור ניטרלי קצר, שאל את שאלה 2 (ריטלין), וסיים עם [[POS: 2]].
  * אם ${pos} == 2 (ריטלין): פלוט [[LOG: meds=yes/no]], תן אישור ניטרלי קצר, שאל את שאלה 3 (עייפות), וסיים עם [[POS: 3]].
  * אם ${pos} == 3 (עייפות): אם עייף ולא מסוגל -> [[FREEZE]] (ללא [[POS]]). אחרת -> [[LOG: tired=no/yes]], שאל שאלה 4 (רגשי), וסיים עם [[POS: 4]].
  * אם ${pos} == 4 (רגשי): תמיכה קלה או הפניה למטפל. אם תקוע -> [[FREEZE]]. אחרת -> שאל שאלה 5 (נושא פתוח), וסיים עם [[POS: 5]].
  * אם ${pos} == 5 (נושא פתוח): לסגור עכשיו -> [[FREEZE]]. לדחות -> [[LOG: parked=topic]], שאל שאלה 6 (פרויקט), וסיים עם [[POS: 6]].
  * אם ${pos} == 6 (פרויקט): זהה מול core/projects.md -> [[LOG: project=name]], שאל שאלה 7 (משימה ראשונה), וסיים עם [[POS: 7]].
  * אם ${pos} == 7 (משימה ראשונה): חדד לצעד קונקרטי ≤30 דקות -> [[LOG: first_task=text]], שאל שאלה 8 (רשימת היום), וסיים עם [[POS: 8]].
  * אם ${pos} == 8 (רשימת היום): תפוס רשימה -> [[LOG: day_list=text]], שאל שאלה 9 (סקירת אתמול), וסיים עם [[POS: 9]].
  * אם ${pos} == 9 (סקירת אתמול): סקור בקצרה מ-ARCHIVE DIGESTS -> שאל שאלה 10 (שער השלמות), וסיים עם [[POS: 10]].
  * אם ${pos} == 10 (שער השלמות): מוכנות מתוך הנאה -> שאל שאלה 11 (משך ומוכנות), וסיים עם [[POS: 11]].
  * אם ${pos} == 11 (משך ומוכנות): פלוט [[LOG: timer_minutes=N]] וסיים עם [[POS: done]].

- הגב בניטרליות ("הבנתי", "רשמתי"), שאל את שאלה ${nextPos}, וסיים עם המרקר [[POS: ${nextPos}]]. ` + keys;
}

return [{ json: { flowBlock: block + tone } }];

const text = ($input.first().json.message?.text || '').trim();
const stateStr = $('Read State').first()?.json?.stdout;
let inEod = false;

if (stateStr) {
  try {
    const state = JSON.parse(stateStr);
    const pos = state.flow?.position;
    inEod = pos === 'eod_1' || pos === 'eod_2' || pos === 'eod_3' || pos === 'archive';
  } catch (e) {}
}

return [{ json: { directArchive: inEod } }];
